import json

def normalise_observation(raw: str, tool_name: str) -> str:
    """
    Normalise a raw tool result into a consistent format.
    Converts empty lists/dicts and raw exceptions into structured responses
    the model can reason about.
    """
    # Try parsing JSON
    try:
        data = json.loads(raw)
    except (json.JSONDecodeError, ValueError):
        # Raw string or exception — wrap it
        return json.dumps({
            "ok": False,
            "tool": tool_name,
            "error": "non-JSON result",
            "raw": raw[:500],   # truncate long tracebacks
        })

    # Detect empty results
    if isinstance(data, dict) and data.get("results") == []:
        return json.dumps({"ok": True, "tool": tool_name, "empty": True, "message": "No results found."})
    if isinstance(data, list) and len(data) == 0:
        return json.dumps({"ok": True, "tool": tool_name, "empty": True, "message": "No results found."})

    # Preserve existing ok/error flags
    if "ok" not in data:
        data["ok"] = True
    data["tool"] = tool_name
    return json.dumps(data)

# Usage
raw1 = json.dumps({"results": []})
print(normalise_observation(raw1, "search"))
# {"ok": true, "tool": "search", "empty": true, "message": "No results found."}

raw2 = "Traceback (most recent call last):\n  ..."
print(normalise_observation(raw2, "get_product"))
# {"ok": false, "tool": "get_product", "error": "non-JSON result", "raw": "Traceback ..."}

raw3 = json.dumps({"price": 99.99, "stock": 42})
print(normalise_observation(raw3, "get_product"))
# {"price": 99.99, "stock": 42, "ok": true, "tool": "get_product"}

import json

def trim_observation(result: str, max_chars: int = 2000) -> str:
    """
    Trim an observation to at most max_chars characters.
    For JSON, tries to preserve top-level structure; for strings, truncates.
    """
    if len(result) <= max_chars:
        return result

    try:
        data = json.loads(result)
    except (json.JSONDecodeError, ValueError):
        # Plain string — truncate with a marker
        return result[:max_chars] + f"\n[... {len(result) - max_chars} chars truncated]"

    # For JSON arrays, keep the first N items
    if isinstance(data, list) and len(data) > 5:
        trimmed = data[:5]
        note = {"_truncated": True, "_kept": 5, "_total": len(data)}
        return json.dumps(trimmed + [note])

    # For JSON dicts, keep all keys but truncate long string values
    if isinstance(data, dict):
        for key, value in data.items():
            if isinstance(value, str) and len(value) > 300:
                data[key] = value[:300] + f"... [{len(value) - 300} chars omitted]"
            elif isinstance(value, list) and len(value) > 10:
                data[key] = value[:10] + [{"_truncated": True, "_total": len(value)}]
        return json.dumps(data)

    return result[:max_chars]

# Example
large = json.dumps({"title": "Paris", "content": "A" * 5000, "views": 9999})
trimmed = trim_observation(large, max_chars=500)
print(len(trimmed), "chars")
# Much shorter than the original 5000+ chars

import anthropic
import json

client = anthropic.Anthropic()

FLIGHTS = {
    "F1": {"airline": "Air France", "price": 550, "seats": 0},   # sold out
    "F2": {"airline": "Delta",      "price": 620, "seats": 4},
    "F3": {"airline": "Lufthansa",  "price": 580, "seats": 2},
}

def get_flight(flight_id: str) -> str:
    flight = FLIGHTS.get(flight_id)
    if not flight:
        return json.dumps({"ok": False, "error": "not found"})
    return json.dumps({"ok": True, "flight_id": flight_id, **flight})

def list_flights(origin: str, destination: str) -> str:
    results = [{"flight_id": fid, **f} for fid, f in FLIGHTS.items()]
    return json.dumps({"ok": True, "flights": results})

TOOLS = [
    {
        "name": "list_flights",
        "description": "List available flights between two cities.",
        "input_schema": {
            "type": "object",
            "properties": {
                "origin": {"type": "string"},
                "destination": {"type": "string"},
            },
            "required": ["origin", "destination"],
        },
    },
    {
        "name": "get_flight",
        "description": "Get details and availability for a specific flight.",
        "input_schema": {
            "type": "object",
            "properties": {"flight_id": {"type": "string"}},
            "required": ["flight_id"],
        },
    },
]

SYSTEM = """
You are a flight booking assistant.
Before booking, check that the flight has seats > 0.
If the cheapest option is sold out, select the next cheapest with seats available.
Think aloud before each action.
"""

messages = [{"role": "user", "content": "Book the cheapest flight from NYC to Paris."}]

for _ in range(8):
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=512,
        system=SYSTEM,
        tools=TOOLS,
        messages=messages,
    )
    messages.append({"role": "assistant", "content": resp.content})

    tool_calls = [b for b in resp.content if b.type == "tool_use"]
    if not tool_calls:
        for block in resp.content:
            if block.type == "text":
                print(block.text)
        break

    results = []
    for block in tool_calls:
        if block.name == "list_flights":
            result = list_flights(**block.input)
        elif block.name == "get_flight":
            result = get_flight(**block.input)
        else:
            result = json.dumps({"error": f"Unknown: {block.name}"})
        results.append({
            "type": "tool_result",
            "tool_use_id": block.id,
            "content": result,
        })
    messages.append({"role": "user", "content": results})

# The model will:
# Step 1: list_flights (observes F1 cheapest at $550)
# Step 2: get_flight(F1) (observes seats=0 — sold out)
# Replan: Step 3: select F3 at $580 (next cheapest with seats)

from datetime import datetime, timezone
import json

def timestamped_result(raw_result: str, tool_name: str) -> str:
    """Wrap a tool result with a fetch timestamp for staleness tracking."""
    try:
        data = json.loads(raw_result)
    except (json.JSONDecodeError, ValueError):
        data = {"raw": raw_result}

    data["_meta"] = {
        "tool": tool_name,
        "fetched_at": datetime.now(timezone.utc).isoformat(),
    }
    return json.dumps(data)

# Example
raw = json.dumps({"stock": 42, "price": 9.99})
wrapped = timestamped_result(raw, "get_product")
print(wrapped)
# {
#   "stock": 42, "price": 9.99,
#   "_meta": {"tool": "get_product", "fetched_at": "2024-06-10T14:30:01Z"}
# }

# The model reads the fetched_at in its Thought:
# "The stock observation is 5 minutes old. Before decrementing stock,
#  I should re-fetch to confirm current availability."
